script:
frappe.ui.form.on('Item', {
    refresh: function(frm) {
        if (!frm.is_new() && frm.doc.has_serial_no) {
            frm.add_custom_button(__('Imprimir Etiqueta'), function() {
                // Gerar etiqueta
                let etiqueta = `
                    <div style="width: 5cm; padding: 10px; border: 1px solid black; font-family: Arial;">
                        <h3 style="margin: 0;">${frm.doc.item_name}</h3>
                        <p style="margin: 5px 0;">Código: ${frm.doc.item_code}</p>
                        <p style="margin: 5px 0;">Tamanho: ${frm.doc.tamanho || '-'}</p>
                        <p style="margin: 5px 0;">Cor: ${frm.doc.cor_principal || '-'}</p>
                        <h2 style="margin: 10px 0;">R$ ${frm.doc.standard_rate.toFixed(2)}</h2>
                    </div>
                `;

                // Abrir em nova janela para impressão
                let win = window.open('', 'Etiqueta', 'width=400,height=300');
                win.document.write(etiqueta);
                win.print();
            });
        }
    }
});
